def main(alert):
    recipients = alert.get('recipients', [])
    if isinstance(recipients, str):
        recipients = [r.strip() for r in recipients.split(',') if r.strip()]
    to_field = alert.get('to', [])
    if isinstance(to_field, str):
        to_field = [r.strip() for r in to_field.split(',') if r.strip()]
    cc_field = alert.get('cc', [])
    if isinstance(cc_field, str):
        cc_field = [r.strip() for r in cc_field.split(',') if r.strip()]
    all_recipients = list(set(recipients + to_field + cc_field))
    return {
        'recipients': all_recipients,
        'count': len(all_recipients),
        'message_id': alert.get('message_id', '')
    }

